// ── Validate required fields ──
if (!input) {
  throw new Error('No input data received');
}

// ── Core scenario logic ──
// Scenario: Invoice overdue 1 day → polite SMS reminder
const output = {
  ...input,
  processed: true,
  processedAt: new Date().toISOString(),
  domain: 'payment-chaser',
  scenario: 'Invoice overdue 1 day → polite SMS reminder',
  gridhandVersion: '1.0',
};

return [{ json: output }];

